import { Link } from 'react-router-dom';

const categories = ['Technology', 'Health', 'Education', 'Environment', 'Art', 'Social Impact'];

export default function Landing() {
  return (
    <div style={{ background: '#0a0d1a' }} className="min-h-screen">
      {/* Hero */}
      <section className="relative px-6 pt-28 pb-32 text-center overflow-hidden">
        <div style={{
          position: 'absolute', inset: 0, opacity: 0.15,
          background: 'radial-gradient(ellipse 80% 60% at 50% -20%, #00d4aa, transparent)'
        }} />
        <div className="relative max-w-4xl mx-auto">
          <div style={{ background: 'rgba(0,212,170,0.1)', border: '1px solid rgba(0,212,170,0.3)', color: '#00d4aa' }}
               className="inline-block px-4 py-1.5 rounded-full text-sm font-medium mb-6">
            ✦ AI-Powered Crowdfunding Platform
          </div>
          <h1 style={{ fontFamily: 'Syne, sans-serif' }}
              className="text-6xl font-black mb-6 leading-none tracking-tight">
            Fund the Future.<br />
            <span style={{ color: '#00d4aa' }}>Backed by AI.</span>
          </h1>
          <p className="text-gray-400 text-xl mb-10 max-w-2xl mx-auto leading-relaxed">
            BackerSphere X uses Google Gemini to evaluate every project for feasibility and success potential.
            Smarter funding decisions. Better outcomes.
          </p>
          <div className="flex gap-4 justify-center flex-wrap">
            <Link to="/register"
              style={{ background: '#00d4aa', color: '#0a0d1a' }}
              className="px-8 py-3.5 rounded-xl font-bold text-lg hover:opacity-90 transition-all shadow-lg">
              Start a Project →
            </Link>
            <Link to="/projects"
              style={{ border: '1px solid #374151', color: '#d1d5db' }}
              className="px-8 py-3.5 rounded-xl font-semibold text-lg hover:border-gray-500 transition-all">
              Browse Projects
            </Link>
          </div>
        </div>
      </section>

      {/* Stats */}
      <section style={{ borderTop: '1px solid #1f2937', borderBottom: '1px solid #1f2937' }} className="py-14">
        <div className="max-w-4xl mx-auto px-6 grid grid-cols-3 gap-8 text-center">
          {[
            { value: '$2.4M+', label: 'Total Funded' },
            { value: '380+', label: 'Projects Launched' },
            { value: '12K+', label: 'Active Backers' },
          ].map(s => (
            <div key={s.label}>
              <div style={{ fontFamily: 'Syne, sans-serif', color: '#00d4aa' }}
                   className="text-4xl font-black mb-1">{s.value}</div>
              <div className="text-gray-500 text-sm uppercase tracking-widest">{s.label}</div>
            </div>
          ))}
        </div>
      </section>

      {/* How It Works */}
      <section className="py-20 px-6 max-w-5xl mx-auto">
        <h2 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold text-center mb-14">
          How BackerSphere X Works
        </h2>
        <div className="grid grid-cols-3 gap-6">
          {[
            { step: '01', title: 'Submit Your Project', desc: 'Innovators submit their idea with goals, timeline, and team details.' },
            { step: '02', title: 'AI Evaluation', desc: 'Gemini AI scores feasibility and success probability instantly.' },
            { step: '03', title: 'Admin Review', desc: 'Admin uses AI insights to approve or reject — then backers fund it.' },
          ].map(s => (
            <div key={s.step} style={{ background: '#111827', border: '1px solid #1f2937' }}
                 className="p-6 rounded-2xl">
              <div style={{ color: '#00d4aa', fontFamily: 'Syne, sans-serif' }} className="text-4xl font-black mb-3 opacity-40">{s.step}</div>
              <h3 className="font-bold text-lg mb-2">{s.title}</h3>
              <p className="text-gray-400 text-sm leading-relaxed">{s.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Categories */}
      <section className="py-12 px-6 max-w-4xl mx-auto text-center">
        <p className="text-gray-500 text-sm uppercase tracking-widest mb-6">Project Categories</p>
        <div className="flex flex-wrap gap-3 justify-center">
          {categories.map(cat => (
            <Link key={cat} to={`/projects?category=${cat}`}
              style={{ background: '#111827', border: '1px solid #1f2937', color: '#9ca3af' }}
              className="px-5 py-2 rounded-full text-sm hover:border-teal-500 hover:text-white transition-all">
              {cat}
            </Link>
          ))}
        </div>
      </section>

      {/* CTA */}
      <section className="py-20 px-6 text-center">
        <div style={{ background: 'linear-gradient(135deg, rgba(0,212,170,0.1), rgba(245,158,11,0.05))', border: '1px solid rgba(0,212,170,0.2)' }}
             className="max-w-2xl mx-auto p-12 rounded-3xl">
          <h2 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold mb-4">Ready to back great ideas?</h2>
          <p className="text-gray-400 mb-8">Join thousands of backers supporting AI-vetted innovations.</p>
          <Link to="/register"
            style={{ background: '#00d4aa', color: '#0a0d1a' }}
            className="px-10 py-3.5 rounded-xl font-bold text-lg inline-block hover:opacity-90 transition-all">
            Join as a Backer
          </Link>
        </div>
      </section>

      <footer style={{ borderTop: '1px solid #1f2937' }} className="py-8 text-center text-gray-600 text-sm">
        © 2024 BackerSphere X · Powered by Google Gemini AI
      </footer>
    </div>
  );
}
